// ============================================================
// HydraNet - Authentication API Route
// Checks Admin, UtilityManager, and DMAManager tables
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'
import { verifyPassword } from '@/lib/auth'

export async function POST(request: NextRequest) {
  try {
    const { email, password } = await request.json()

    if (!email || !password) {
      return NextResponse.json(
        { error: 'Email and password are required' },
        { status: 400 }
      )
    }

    // Try to find user in Admin table
    const admin = await prisma.admin.findUnique({
      where: { email },
    })

    if (admin) {
      // Check if admin is active
      if (admin.status !== 'active') {
        return NextResponse.json(
          { error: 'Account is inactive. Please contact administrator.' },
          { status: 403 }
        )
      }

      // Verify password
      const isValid = await verifyPassword(password, admin.password)
      if (!isValid) {
        return NextResponse.json(
          { error: 'Invalid email or password' },
          { status: 401 }
        )
      }

      // Return admin user
      return NextResponse.json({
        user: {
          id: admin.id,
          email: admin.email,
          name: admin.name,
          phone: admin.phone,
          avatar: admin.avatar,
          status: admin.status,
          createdAt: admin.createdAt,
          updatedAt: admin.updatedAt,
          role: 'admin',
        },
        message: 'Login successful',
      })
    }

    // Try to find user in UtilityManager table
    const utilityManager = await prisma.utilityManager.findUnique({
      where: { email },
      include: {
        utility: {
          select: { id: true, name: true },
        },
      },
    })

    if (utilityManager) {
      // Check if manager is active
      if (utilityManager.status !== 'active') {
        return NextResponse.json(
          { error: 'Account is inactive. Please contact administrator.' },
          { status: 403 }
        )
      }

      // Verify password
      const isValid = await verifyPassword(password, utilityManager.password)
      if (!isValid) {
        return NextResponse.json(
          { error: 'Invalid email or password' },
          { status: 401 }
        )
      }

      // Return utility manager user
      return NextResponse.json({
        user: {
          id: utilityManager.id,
          email: utilityManager.email,
          name: utilityManager.name,
          phone: utilityManager.phone,
          avatar: utilityManager.avatar,
          status: utilityManager.status,
          createdAt: utilityManager.createdAt,
          updatedAt: utilityManager.updatedAt,
          role: 'utility_manager',
          utilityId: utilityManager.utility?.id || null,
          utilityName: utilityManager.utility?.name || null,
        },
        message: 'Login successful',
      })
    }

    // Try to find user in DMAManager table
    const dmaManager = await prisma.dMAManager.findUnique({
      where: { email },
      include: {
        utility: {
          select: { id: true, name: true },
        },
        dma: {
          select: { id: true, name: true },
        },
      },
    })

    if (dmaManager) {
      // Check if manager is active
      if (dmaManager.status !== 'active') {
        return NextResponse.json(
          { error: 'Account is inactive. Please contact administrator.' },
          { status: 403 }
        )
      }

      // Verify password
      const isValid = await verifyPassword(password, dmaManager.password)
      if (!isValid) {
        return NextResponse.json(
          { error: 'Invalid email or password' },
          { status: 401 }
        )
      }

      // Return DMA manager user
      return NextResponse.json({
        user: {
          id: dmaManager.id,
          email: dmaManager.email,
          name: dmaManager.name,
          phone: dmaManager.phone,
          avatar: dmaManager.avatar,
          status: dmaManager.status,
          createdAt: dmaManager.createdAt,
          updatedAt: dmaManager.updatedAt,
          role: 'dma_manager',
          utilityId: dmaManager.utility.id,
          utilityName: dmaManager.utility.name,
          dmaId: dmaManager.dma?.id || null,
          dmaName: dmaManager.dma?.name || null,
        },
        message: 'Login successful',
      })
    }

    // Try to find user in Engineer table (includes engineers and team leaders)
    const engineer = await prisma.engineer.findUnique({
      where: { email },
      include: {
        branch: {
          select: { id: true, name: true },
        },
        dma: {
          select: { id: true, name: true },
        },
        team: {
          select: { id: true, name: true },
        },
      },
    })

    if (engineer) {
      // Check if engineer is active
      if (engineer.status !== 'active') {
        return NextResponse.json(
          { error: 'Account is inactive. Please contact administrator.' },
          { status: 403 }
        )
      }

      // Verify password
      const isValid = await verifyPassword(password, engineer.password)
      if (!isValid) {
        return NextResponse.json(
          { error: 'Invalid email or password' },
          { status: 401 }
        )
      }

      // Determine role based on whether they're a team leader
      const role = engineer.role === 'team_leader' ? 'team_leader' : 'engineer'

      // Return engineer user
      return NextResponse.json({
        user: {
          id: engineer.id,
          email: engineer.email,
          name: engineer.name,
          phone: engineer.phone,
          status: engineer.status,
          createdAt: engineer.createdAt,
          updatedAt: engineer.updatedAt,
          role: role,
          branchId: engineer.branchId,
          branchName: engineer.branch.name,
          dmaId: engineer.dmaId,
          dmaName: engineer.dma.name,
          teamId: engineer.teamId,
          teamName: engineer.team?.name || null,
        },
        message: 'Login successful',
      })
    }

    // No user found in any table
    return NextResponse.json(
      { error: 'Invalid email or password' },
      { status: 401 }
    )
  } catch (error) {
    console.error('Login error:', error)
    return NextResponse.json(
      { error: 'Internal server error. Please try again later.' },
      { status: 500 }
    )
  }
}